    fseek(f, vstore_offset_pos, SEEK_SET);
    write_uint8(f, 0x1C);
    write_uint16(f, (uint16_t)vstore_offset);
    write_uint8(f, 0x18);
    fseek(f, 0, SEEK_END);

    uint32_t cff_end = ftell(f);
    fseek(f, cff_offset_pos, SEEK_SET);
    write_uint32(f, cff_start);
    write_uint32(f, cff_end - cff_start);

    fclose(f);
    return 0;
}
